import logging
from logging.handlers import RotatingFileHandler
import os
import stat

# setup log storage location
log_file_path = "/path/to/log_file.log"

# set up log rotation
handler = RotatingFileHandler(log_file_path, maxBytes=5000, backupCount=5)
formatter = logging.Formatter('%(asctime)s - %(name)s - %(levelname)s - %(message)s')
handler.setFormatter(formatter)

# add handler to the logger
logger = logging.getLogger('Application Logger')
logger.setLevel(logging.DEBUG)
logger.addHandler(handler)

# log sample messages
logger.debug('debug log')
logger.info('info log')
logger.warning('warning log')
logger.error('error log')
logger.critical('critical log')


# change file permission to read-write for owner only (600)
os.chmod(log_file_path, stat.S_IRUSR | stat.S_IWUSR)